const body = $input.first().json.body;
if (!body.ache_signal || !body.ache_signal.trim()) {
  throw new Error('τ-anchor required: ache_signal cannot be empty. Manifold Autarky risk.');
}
const sessionId = body.session_id || `session_${Date.now()}_${Math.floor(Math.random()*9999)}`;
return [{
  json: {
    tau: {
      ache_signal: body.ache_signal,
      mortal_asymmetry: 1,
      ids_score: body.ids_score || null,
      primary_cluster: body.primary_cluster || null
    },
    prompt: body.prompt,
    models: body.models || ['claude-sonnet-4-6', 'gpt-4o', 'deepseek-chat'],
    session_id: sessionId,
    timestamp: Date.now()
  }
}];

const data = $input.first().json;
const cmcp = {
  version: '1.0',
  session_id: data.session_id,
  tau_anchor: { ache_vector: data.tau.ache_signal, mortal_asymmetry: 1 },
  ids_context: { score: data.tau.ids_score, cluster: data.tau.primary_cluster },
  constitutional_clauses: ['clause_005'],
  timestamp: data.timestamp
};
const forClaude = (p) => `<rsps_context version="${p.version}">\n<tau_anchor>\n  <ache_vector>${p.tau_anchor.ache_vector}</ache_vector>\n  <session>${p.session_id}</session>\n</tau_anchor>\n<ids_context><score>${p.ids_context.score || 'N/A'}</score><cluster>${p.ids_context.cluster || 'N/A'}</cluster></ids_context>\n</rsps_context>\n\n`;
const forDefault = (p) => `[RSPS CONTEXT | session:${p.session_id}]\nTAU_INTENT: ${p.tau_anchor.ache_vector}\nIDS: ${p.ids_context.score || 'N/A'} | CLUSTER: ${p.ids_context.cluster || 'N/A'}\n---\n\n`;
return [{
  json: {
    ...data,
    cmcp_packet: cmcp,
    prompts: {
      claude: forClaude(cmcp) + data.prompt,
      default: forDefault(cmcp) + data.prompt
    }
  }
}];

const data = $input.first().json;
const models = data.models.slice(0, 3);
return models.map((modelId, i) => ({
  json: {
    ...data,
    _target_model: modelId,
    _branch_index: i,
    _prompt: modelId.includes('claude') ? data.prompts.claude : data.prompts.default
  }
}));

const item = $input.first().json;
const content = item.choices?.[0]?.message?.content || `[ERROR: No response from ${item._target_model}]`;
const wordCount = Math.max(1, content.split(/\s+/).length);
const fearP = [/\bI (cannot|can't|won't|am unable to)\b/gi, /\b(dangerous|harmful) (to|for)\b/gi];
const egoP  = [/\b(clearly|obviously|certainly|undoubtedly)\b/gi, /\bThere is no doubt\b/gi];
const biasP = [/\b(normal|typical|standard) (person|people)\b/gi];
const count = (text, patterns) => patterns.reduce((n, p) => n + (text.match(p)||[]).length, 0);
const fearScore = Math.min(1, count(content, fearP) / (wordCount * 0.015));
const egoScore  = Math.min(1, count(content, egoP)  / (wordCount * 0.015));
const biasScore = Math.min(1, count(content, biasP) / (wordCount * 0.010));
const conf = Math.max(0.1, 1 - (fearScore * 0.9 + egoScore * 1.3 + biasScore * 0.8) / 3);
const flags = [];
if (fearScore > 0.25) flags.push(`FEAR(${fearScore.toFixed(2)})`);
if (egoScore  > 0.20) flags.push(`EGO(${egoScore.toFixed(2)})`);
if (biasScore > 0.25) flags.push(`BIAS(${biasScore.toFixed(2)})`);
return [{ json: {
  model_id: item._target_model || 'unknown',
  content,
  dcfb: { fear_score: fearScore, ego_score: egoScore, bias_score: biasScore, confidence_weight: conf, flags },
  _session_id: item._session_id,
  _branch_index: item._branch_index
}}];

const items = $input.all();
if (items.length < 3) {
  return [{ json: { error: `Need 3 outputs, got ${items.length}`, outputs: items.map(i=>i.json) } }];
}
const outputs = items.slice(0,3).map(i => i.json);
const [a, b, c] = outputs;
const wordVec = (text) => {
  const words = text.toLowerCase().match(/\b\w{4,}\b/g) || [];
  const freq = {};
  words.forEach(w => freq[w] = (freq[w]||0)+1);
  return freq;
};
const cosine = (va, vb) => {
  const keys = new Set([...Object.keys(va), ...Object.keys(vb)]);
  let dot=0, na=0, nb=0;
  keys.forEach(k => { const x=va[k]||0, y=vb[k]||0; dot+=x*y; na+=x*x; nb+=y*y; });
  return na&&nb ? dot/(Math.sqrt(na)*Math.sqrt(nb)) : 0;
};
const wA=a.dcfb?.confidence_weight||1, wB=b.dcfb?.confidence_weight||1, wC=c.dcfb?.confidence_weight||1;
const vA=wordVec(a.content||''), vB=wordVec(b.content||''), vC=wordVec(c.content||'');
const simAB=cosine(vA,vB)*((wA+wB)/2);
const simBC=cosine(vB,vC)*((wB+wC)/2);
const simCA=cosine(vC,vA)*((wC+wA)/2);
const gm = Math.pow(Math.max(0,simAB)*Math.max(0,simBC)*Math.max(0,simCA), 1/3);
const kappa = Math.min(1, Math.max(0, 1-gm));
const level = kappa<0.10?'FLAT':kappa<0.20?'MARGINAL':kappa<0.35?'HOLD':'ESCHER';
const pairSims = {'A↔B':simAB,'B↔C':simBC,'C↔A':simCA};
const weakest = Object.entries(pairSims).sort((x,y)=>x[1]-y[1])[0][0];
return [{ json: {
  session_id: a._session_id,
  triangle_residue: {
    kappa: parseFloat(kappa.toFixed(4)),
    level,
    is_congruent: ['FLAT','MARGINAL'].includes(level),
    sim_ab: parseFloat(simAB.toFixed(4)),
    sim_bc: parseFloat(simBC.toFixed(4)),
    sim_ca: parseFloat(simCA.toFixed(4)),
    weakest_link: weakest
  },
  outputs: outputs.map(o => ({ model_id:o.model_id, content:o.content, dcfb_confidence:o.dcfb?.confidence_weight, flags:o.dcfb?.flags||[] }))
}}];

const data = $input.first().json;
const tr = data.triangle_residue;
const violations = [];
const clauses_checked = ['clause_003', 'clause_005'];
if (!tr.is_congruent && !tr.weakest_link) {
  violations.push('clause_005: Rejection pending without structural analysis');
}
const r_score = violations.length === 0 ? (tr.is_congruent ? 1.0 : 0.75) : 0.30;
const outcome = violations.length>0 ? 'FAILED' : r_score>=0.75 ? 'PASSED' : 'DEFERRED';
const bestOutput = data.outputs.reduce((best, o) => 
  (o.dcfb_confidence||0) > (best.dcfb_confidence||0) ? o : best, data.outputs[0]);
return [{ json: {
  ...data,
  aurora: { r_score, clauses_checked, violations, outcome },
  recommended_synthesis: `[${bestOutput?.model_id}]: ${bestOutput?.content?.slice(0,200)}...`
}}];

const data = $input.first().json;
const tr = data.triangle_residue;
return [{ json: {
  session_id: data.session_id,
  outputs: data.outputs,
  triangle_residue: tr,
  aurora: data.aurora,
  recommended_synthesis: data.recommended_synthesis,
  tau_review_required: ['HOLD','ESCHER'].includes(tr.level),
  cmcp_next: {
    session_id: data.session_id,
    prior_kappa: tr.kappa,
    prior_level: tr.level,
    aurora_outcome: data.aurora.outcome
  },
  timestamp: Date.now()
}}];
